// --- Orders ---
async function saveOrderToDB(orderData) {
    if (!supabaseClient) {
        console.warn("Bestellung wurde lokal gespeichert (Keine Supabase Verbindung).");
        return false;
    }

    try {
        console.log("DB: Sende Bestellung nach Supabase...", orderData.order_id);
        const { data, error } = await supabaseClient
            .from('orders')
            .insert([orderData]);

        if (error) {
            console.error("❌ Supabase Fehler (Orders):", error.message, error.details);
            return false;
        }
        console.log("✅ Bestellung erfolgreich nach Supabase übertragen.");
        return true;
    } catch (e) {
        console.error("❌ Schwerer Fehler beim Speichern der Bestellung:", e);
        return false;
    }
}

async function loadOrdersFromDB() {
    if (!supabaseClient) return null;

    try {
        const { data, error } = await supabaseClient
            .from('orders')
            .select('*')
            .order('created_at', { ascending: false });

        if (error) throw error;
        return data;
    } catch (e) {
        console.error("Error loading orders from DB:", e);
        return null;
    }
}

async function updateOrderStatus(orderId, newStatus, trackingId = null) {
    if (!supabaseClient) return false;

    try {
        const updateData = {};
        if (newStatus) updateData.status = newStatus;
        if (trackingId !== null) updateData.tracking_id = trackingId;

        const { data, error } = await supabaseClient
            .from('orders')
            .update(updateData)
            .eq('order_id', orderId);

        if (error) throw error;
        return true;
    } catch (e) {
        console.error("Error updating order status:", e);
        return false;
    }
}

